var row = (msg.payload && msg.payload[0]) ? msg.payload[0] : {};

function val(v) {
    var f = parseFloat(v);
    return (!isNaN(f)) ? f : 'NULL';
}

msg.topic = [
    "INSERT INTO estado_silos (fecha, hora, nombre, vacio) VALUES",
    " (DATE(NOW()), DATE_FORMAT(NOW(),'%H:00'), 'Silo A', " + val(row.silo_a) + "),",
    " (DATE(NOW()), DATE_FORMAT(NOW(),'%H:00'), 'Silo B', " + val(row.silo_b) + "),",
    " (DATE(NOW()), DATE_FORMAT(NOW(),'%H:00'), 'Silo C', " + val(row.silo_c) + "),",
    " (DATE(NOW()), DATE_FORMAT(NOW(),'%H:00'), 'Silo E', " + val(row.silo_e) + ")",
    " ON DUPLICATE KEY UPDATE vacio = VALUES(vacio)"
].join("");

return msg;
